const reducePower = flow.get('reduce_power') || false;
const rand = (min, max, d = 2) =>
    Number((Math.random() * (max - min) + min).toFixed(d));

const t = Date.now() / 1000;
const sine = Math.sin((t * Math.PI) / 60);

const prevMode = flow.get('last_mode') || 'NORMAL';
const curMode = reducePower ? 'ECO' : 'NORMAL';
if (prevMode !== curMode) {
    flow.set('transition_step', 0);
    flow.set('last_mode', curMode);
}
const step = Math.min((flow.get('transition_step') || 0) + 1, 20);
flow.set('transition_step', step);
const ratio = step / 20;

const tgt = reducePower ? {
    pwr: 2.5 + sine * 0.8, load: 32 + sine * 9,
    cur: 5.5 + sine * 1.5, pf: 0.96
} : {
    pwr: 7.8 + sine * 1.7, load: 70 + sine * 14,
    cur: 14 + sine * 3.0, pf: 0.89 + sine * 0.05
};

const lerp = (a, b, r) => a + (b - a) * r;
const prev = {
    pwr: flow.get('prev_pwr') ?? tgt.pwr,
    load: flow.get('prev_load') ?? tgt.load,
    cur: flow.get('prev_cur') ?? tgt.cur,
    pf: flow.get('prev_pf') ?? tgt.pf
};
const base = {
    pwr: lerp(prev.pwr, tgt.pwr, ratio),
    load: lerp(prev.load, tgt.load, ratio),
    cur: lerp(prev.cur, tgt.cur, ratio),
    pf: lerp(prev.pf, tgt.pf, ratio)
};
flow.set('prev_pwr', base.pwr); flow.set('prev_load', base.load);
flow.set('prev_cur', base.cur); flow.set('prev_pf', base.pf);

const spikeNow = !reducePower && Math.random() < 0.10;
const spikeX = spikeNow ? rand(1.3, 1.8) : 1.0;
const noise = (v, pct) => v * (1 + (Math.random() - 0.5) * pct / 100);

const activePow = Number(Math.max(0.5, noise(base.pwr * spikeX, 3)).toFixed(3));
const load_pct = Number(Math.min(100, Math.max(5, noise(base.load * spikeX, 4))).toFixed(1));
const curBase = noise(base.cur * spikeX, 5);
const l1 = Number((curBase + rand(-0.4, 0.4)).toFixed(2));
const l2 = Number((curBase + rand(-0.3, 0.5)).toFixed(2));
const l3 = Number((curBase + rand(-0.5, 0.3)).toFixed(2));
const pf = Number(Math.min(0.99, Math.max(0.78, noise(base.pf, 2))).toFixed(3));

const voltSag = reducePower ? 0 : (load_pct - 50) * 0.03;
const overcurrent = l1 > 17.5 || l2 > 17.5 || l3 > 17.5;

let statusLabel = reducePower ? `ECO (${Math.round(ratio * 100)}%)` : 'NORMAL';
if (spikeNow) statusLabel = 'NORMAL ⚡SPIKE';
if (overcurrent) statusLabel = 'NORMAL ⚠OVERCURRENT';

msg.payload = {
    machine_id: 'MC-01',
    ts: new Date(Date.now() + 7 * 60 * 60 * 1000).toISOString().replace('Z', '+07:00'),
    voltage_v: { l1: Number((rand(229, 232, 1) - voltSag).toFixed(1)), l2: Number((rand(228, 231, 1) - voltSag).toFixed(1)), l3: Number((rand(230, 233, 1) - voltSag).toFixed(1)) },
    current_a: { l1, l2, l3 },
    frequency_hz: rand(49.8, 50.2, 2),
    power_factor: pf,
    active_power_kw: activePow,
    reactive_power_kvar: Number((activePow * Math.tan(Math.acos(pf))).toFixed(3)),
    apparent_power_kva: Number((activePow / pf).toFixed(3)),
    energy_today_kwh: Number(((flow.get('energy_acc') || 0) + activePow * 5 / 3600).toFixed(4)),
    motor_rpm: Math.round(reducePower ? lerp(1200, 1380, ratio) + rand(-15, 15) : 1480 + rand(-20, 15)),
    load_pct,
    alarm_overcurrent: overcurrent,
    spike_event: spikeNow,
    power_mode: reducePower ? 'ECO' : 'NORMAL',
    status_label: statusLabel,
    transition_pct: Math.round(ratio * 100),
    reduce_power_active: reducePower,
    source: 'node-red-energy-simulator'
};
flow.set('energy_acc', msg.payload.energy_today_kwh);
return msg;

msg.headers = { 'Content-Type': 'application/json', 'ngrok-skip-browser-warning': 'true' };
msg.payload = { event: 'machine_energy_telemetry', source: 'node-red', topic: 'smartfactory/MC-01/energy/telemetry', data: msg.payload };
return msg;

const d = msg.payload;
const maxCur = Math.max(d.current_a.l1, d.current_a.l2, d.current_a.l3);
const pfPct  = Math.round(d.power_factor * 100);

const mPwr   = { payload: d.active_power_kw };
const mPF    = { payload: pfPct };
const mLoad  = { payload: d.load_pct };
const mCur   = { payload: Number(maxCur.toFixed(2)) };
const mRpm   = { payload: d.motor_rpm };

// chart ส่งหลายเส้น
const mChart1 = { payload: d.active_power_kw, topic: 'Power kW' };
const mChart2 = { payload: d.load_pct / 10,   topic: 'Load x0.1%' };

// status banner
const alarm = d.alarm_overcurrent || d.spike_event;
const mBanner = {
    payload: d.status_label,
    style: alarm ? { color: '#e74c3c', 'font-weight': 'bold' } : {}
};

return [mPwr, mPF, mLoad, mCur, mRpm, mChart1, mChart2, mBanner];

const body = msg.payload || {};
const reducePower = body.reduce_power === true;

flow.set('reduce_power', reducePower);
flow.set('last_analysis', body);

// output 1 → http response (ต้องรักษา msg.res)
msg.statusCode = 200;
msg.payload = { status: 'ok', reduce_power: reducePower, ts: new Date().toISOString() };

// output 2 → UI nodes
const uiMsg = { payload: body };

return [msg, uiMsg];

const b = msg.payload || {};
const reduce = b.reduce_power === true;

const riskColor = { high: '#e74c3c', medium: '#f39c12', low: '#27ae60' };
const risk = (b.risk_level || 'low').toLowerCase();

const mMode = {
    payload: reduce ? '🔴 ECO MODE — ลดการใช้พลังงาน' : '🟢 NORMAL — ทำงานปกติ',
    style: { color: reduce ? '#e74c3c' : '#27ae60', 'font-weight': 'bold', 'font-size': '16px' }
};
const mRisk        = { payload: `⚠ Risk: ${(b.risk_level||'low').toUpperCase()}  |  readings: ${b.readings_count||'-'}  |  วิเคราะห์: ${b.analyzed_at ? b.analyzed_at.substring(11,19) : '-'} UTC` };
const mReason      = { payload: b.reason         || '-' };
const mRecommend   = { payload: b.recommendation  || '-' };
const mSummary     = { payload: b.summary         || '-' };

return [mMode, mRisk, mReason, mRecommend, mSummary];
